import{_ as t,o,c as i,a2 as a}from"./chunks/framework.CHeM0PsO.js";const u=JSON.parse('{"title":"RFC 0071 — SQLite at-rest encryption (opt-in, single-key)","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0071-sqlite-at-rest-encryption.md","filePath":"rfcs/0071-sqlite-at-rest-encryption.md"}'),s={name:"rfcs/0071-sqlite-at-rest-encryption.md"};function n(r,e,d,c,l,p){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="rfc-0071-—-sqlite-at-rest-encryption-opt-in-single-key" tabindex="-1">RFC 0071 — SQLite at-rest encryption (opt-in, single-key) <a class="header-anchor" href="#rfc-0071-—-sqlite-at-rest-encryption-opt-in-single-key" aria-label="Permalink to &quot;RFC 0071 — SQLite at-rest encryption (opt-in, single-key)&quot;">​</a></h1><p><strong>Status:</strong> Implemented<br><strong>Date:</strong> July 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> packages/db, apps/auth, packages/manifest, runtime/src, bin/sv (scripts), Docker/Compose, <code>.env.example</code>, docs; a scoped implementation of RFC 0008 Tier 2b, amends RFC 0008; relates to RFC 0004 (per-plugin database) and RFC 0060 (client-side encryption)<br><strong>Incorporated into plan:</strong> Yes — epic task 8.14. Carves the SQLite-only, whole-file at-rest slice out of RFC 0008&#39;s Tier 2 into a small, shippable, opt-in feature. Postgres at-rest, avatar/blob encryption, and field-level <code>sdk.crypto</code> (Tier 3) remain in the broader Task 8.5.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Add an <strong>opt-in, operator-owned, whole-file encryption</strong> option for Sovereign&#39;s SQLite databases, using SQLCipher (via <code>better-sqlite3-multiple-ciphers</code>) keyed by a single instance-wide key supplied as an environment variable. When the key is absent — the <strong>default</strong> — nothing changes: databases stay plaintext exactly as today. When the key is set, every SQLite database the instance owns (<code>sovereign.db</code>, <code>auth.db</code>, and every <code>database: &quot;isolated&quot;</code> plugin&#39;s file) is encrypted at rest, transparently to all query code above the driver.</p><p>A plugin may additionally declare <code>requireEncryption: true</code> in its manifest to <strong>force encryption on for its own isolated database</strong> regardless of the instance-wide default — a raise-only control (a plugin can demand encryption, it can never opt out of encryption the operator has enabled).</p><p>This is deliberately the <strong>narrow, honest slice</strong> of RFC 0008&#39;s Tier 2: it protects a stolen disk, a leaked volume snapshot, or a copied database file. It does <strong>not</strong> protect against a live compromised process or an operator who holds the key — that is Tier 4 / client-side encryption (RFC 0060), which already ships opt-in per plugin. The two are complementary and independent.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>RFC 0008 charted at-rest encryption (Tier 2) but folded it into one large, crypto-heavy, post-v1 task (8.5) spanning a KEK→DEK envelope hierarchy, both database engines, avatar/blob encryption, and field-level encryption. That scope is the reason it keeps being deferred.</p><p>The great majority of self-hosted Sovereign instances run the <strong>zero-config SQLite default</strong> (<code>docs/self-hosting.md</code>: &quot;SQLite is the zero-config default and is fine for personal and small-group use&quot;). For those instances, <code>docs/security.md</code> currently tells operators plainly that their data is <strong>not encrypted at rest</strong> and to rely on host-level disk encryption. That is a real gap for the exact deployments Sovereign is most often run as, and it is closable with a small, well-scoped change rather than the full Tier 2 programme:</p><ul><li>SQLite has a mature, drop-in encrypted driver (<code>better-sqlite3-multiple-ciphers</code>) that is API-compatible with the <code>better-sqlite3</code> we already use.</li><li>The native build toolchain SQLCipher needs is <strong>already present</strong> in both Dockerfiles (<code>apk add python3 make g++</code>), because <code>better-sqlite3</code> has no Alpine/musl prebuild and is already compiled from source.</li><li>We already have a proven single-key AES-GCM envelope pattern and a no-default, fail-fast key-loading discipline in <code>runtime/src/secrets.ts</code> (<code>SOVEREIGN_VAULT_KEY</code>).</li></ul><p>Shipping this as an opt-in feature gives operators a verifiable &quot;stolen disk yields ciphertext&quot; guarantee without waiting for the full envelope/field-level machinery, and without changing anything for operators who don&#39;t enable it.</p><h2 id="current-state-what-this-builds-on" tabindex="-1">Current state (what this builds on) <a class="header-anchor" href="#current-state-what-this-builds-on" aria-label="Permalink to &quot;Current state (what this builds on)&quot;">​</a></h2><p>Every place the codebase opens a raw SQLite connection (grep for <code>new Database(</code>):</p><table tabindex="0"><thead><tr><th>Call site</th><th>Database</th></tr></thead><tbody><tr><td><code>packages/db/src/client.ts:46</code></td><td>Platform DB (<code>sovereign.db</code>)</td></tr><tr><td><code>apps/auth/src/db.ts:68</code></td><td>Auth DB (<code>auth.db</code>)</td></tr><tr><td><code>packages/db/src/plugin-client.ts:98</code></td><td>Isolated plugin DBs (<code>database: &quot;isolated&quot;</code>, one <code>.db</code> file per plugin)</td></tr><tr><td><code>scripts/reset-mfa.ts:25</code></td><td>Break-glass MFA reset — opens <code>auth.db</code> <strong>directly, outside the app</strong></td></tr><tr><td><code>scripts/seed.ts:84</code></td><td>Dev seed script</td></tr></tbody></table><p>Load-bearing facts the design rests on:</p><ul><li><strong>better-auth does not open its own connection.</strong> <code>apps/auth/src/auth.ts</code> passes <code>database: getAuthDatabase()</code> — the already-opened <code>better-sqlite3</code> handle from <code>apps/auth/src/db.ts</code>. better-auth drives that handle internally (Kysely). So if the handle is opened with the cipher key applied <strong>before</strong> better-auth receives it, better-auth&#39;s own migrations (<code>getMigrations</code>/<code>runMigrations</code> in <code>apps/auth/src/migrate.ts</code>) and queries ride along transparently. Confirmed empirically (Adoption path, Phase C) — better-auth&#39;s own migrator and queries work cleanly against an encrypted <code>auth.db</code>.</li><li><strong>The Docker toolchain is already there.</strong> Both <code>Dockerfile</code> and <code>apps/auth/Dockerfile</code> install <code>python3 make g++</code> specifically for <code>better-sqlite3</code>&#39;s from-source musl build. <code>better-sqlite3-multiple-ciphers</code> uses the identical <code>bindings</code> + <code>prebuild-install</code> shape and the same toolchain, tracks the same version line (<code>12.x</code>), and is MIT-licensed.</li><li><strong><code>allowBuilds</code> gates native builds.</strong> <code>pnpm-workspace.yaml</code> lists <code>better-sqlite3: true</code>; the cipher fork needs an equivalent entry.</li><li><strong>Single-key AES-GCM envelope precedent.</strong> <code>runtime/src/secrets.ts</code> (<code>SOVEREIGN_VAULT_KEY</code>, <code>vaultKeyFromEnv()</code>, <code>sv1:iv:tag:ciphertext</code>) and its self-contained twin <code>apps/auth/src/crypto-envelope.ts</code> already establish the key encoding (base64 / base64url / 64-char hex → 32 bytes), the no-default fail-fast rule, and the &quot;each process reads its own env&quot; pattern. The DB key loader mirrors this exactly.</li><li><strong>The manifest <code>database</code> field</strong> (<code>packages/manifest/src/schema.ts:47-51</code>) is either <code>&#39;shared&#39; | &#39;isolated&#39;</code> or <code>{ isolation, dialect }</code>. This is where <code>requireEncryption</code> attaches.</li><li><strong>Backups are file copies.</strong> <code>docs/self-hosting.md</code>: dev backup is copying <code>./data/</code>; prod is a named-volume snapshot. Once the files are encrypted, those copies are automatically ciphertext.</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="_1-single-instance-key-opt-in-off-by-default" tabindex="-1">1. Single instance key, opt-in, off by default <a class="header-anchor" href="#_1-single-instance-key-opt-in-off-by-default" aria-label="Permalink to &quot;1. Single instance key, opt-in, off by default&quot;">​</a></h3><p>A new environment variable — <code>SOVEREIGN_DB_ENCRYPTION_KEY</code> — holds a single 32-byte key (base64 / base64url / 64-char hex, decoded by the same <code>decodeKey()</code> logic as <code>SOVEREIGN_VAULT_KEY</code>).</p><ul><li><strong>Absent (default):</strong> SQLite databases open in plaintext exactly as today. No behaviour change, no new dependency cost at runtime.</li><li><strong>Present:</strong> every SQLite database the instance owns is opened with the cipher key applied (SQLCipher <code>PRAGMA key</code>), before any query or migration runs.</li></ul><p>Presence of the key <strong>is</strong> the toggle — no separate boolean flag, matching the project&#39;s existing &quot;a feature that needs a secret fails closed without it, works with it&quot; convention. The same key encrypts all SQLite databases (platform, auth, and every isolated plugin DB), by explicit design choice for operational simplicity (see Alternatives for the per-DB-key option and its rejection).</p><h3 id="_2-sqlcipher-via-better-sqlite3-multiple-ciphers" tabindex="-1">2. SQLCipher via <code>better-sqlite3-multiple-ciphers</code> <a class="header-anchor" href="#_2-sqlcipher-via-better-sqlite3-multiple-ciphers" aria-label="Permalink to &quot;2. SQLCipher via `better-sqlite3-multiple-ciphers`&quot;">​</a></h3><p>Replace the <code>better-sqlite3</code> import at the five call sites with a small shared opener that:</p><ol><li>imports <code>better-sqlite3-multiple-ciphers</code> (API-compatible constructor);</li><li>if <code>SOVEREIGN_DB_ENCRYPTION_KEY</code> is set, explicitly selects the SQLCipher-compatible cipher (<code>PRAGMA cipher=&#39;sqlcipher&#39;</code>) before keying — the driver supports several cipher schemes and defaults to its own (&quot;sqleet&quot;), not SQLCipher, so this must be set every time rather than relying on the default (see Open question 2&#39;s resolution) — then applies the key via <code>.key()</code>, before any other statement;</li><li>sets the existing pragmas (<code>journal_mode = WAL</code>, <code>foreign_keys = ON</code>);</li><li>is the single chokepoint all five sites call, so keying (and the cipher selection) can never be accidentally skipped at one site.</li></ol><p>The opener lives in <code>packages/db</code> (the natural home; <code>apps/auth</code> keeps its self-contained copy for the same reason <code>crypto-envelope.ts</code> is duplicated — <code>apps/auth</code> does not depend on <code>runtime</code>/<code>packages/db</code>).</p><h3 id="_3-state-marker-mismatch-guard-fail-fast-both-directions" tabindex="-1">3. State-marker mismatch guard (fail-fast, both directions) <a class="header-anchor" href="#_3-state-marker-mismatch-guard-fail-fast-both-directions" aria-label="Permalink to &quot;3. State-marker mismatch guard (fail-fast, both directions)&quot;">​</a></h3><p>Silent key/state mismatches are the dangerous failure mode: opening an encrypted file without the key looks like corruption, and opening a plaintext file &quot;with encryption on&quot; would silently write new plaintext into a file the operator believes is encrypted.</p><p>On first encrypted boot, write a small <strong>marker</strong> recording that the data directory is encrypted (a sentinel file under the data dir, e.g. <code>data/.db-encrypted</code>, or an equivalent metadata row). On every boot, compare the marker against the presence of the key:</p><table tabindex="0"><thead><tr><th>Marker says</th><th>Key present</th><th>Pre-existing SQLite files?</th><th>Action</th></tr></thead><tbody><tr><td>plaintext</td><td>no</td><td>—</td><td>Normal plaintext boot.</td></tr><tr><td>encrypted</td><td>yes</td><td>—</td><td>Normal encrypted boot.</td></tr><tr><td>encrypted</td><td>no</td><td>—</td><td><strong>Fail-fast:</strong> &quot;databases are encrypted but <code>SOVEREIGN_DB_ENCRYPTION_KEY</code> is not set.&quot;</td></tr><tr><td>plaintext</td><td>yes</td><td>yes</td><td><strong>Fail-fast:</strong> existing plaintext data — run the migration tool first (see §6).</td></tr><tr><td>plaintext</td><td>yes</td><td>no</td><td><strong>Write the marker and proceed</strong> — a fresh instance enabling encryption before its first boot (§6 &quot;Enabling on a fresh instance&quot;) has nothing plaintext to protect, so there is nothing to fail <em>fast about</em>; every file it creates from here on is opened with the key already applied.</td></tr></tbody></table><p>The last row exists because the first four alone made &quot;fresh instance, key set from day one&quot; indistinguishable from &quot;existing plaintext instance&quot; — both are &quot;marker absent, key present&quot; — which blocked the very onboarding path this RFC documents. <code>hasExistingSqliteFiles()</code> (checks for <code>sovereign.db</code>, <code>auth.db</code>, or any <code>plugins/*.db</code>) is what tells the two apart.</p><p>A wrong (but present) key surfaces as SQLCipher failing to read the header; the opener translates that into a distinct, actionable error rather than a generic &quot;file is not a database&quot;.</p><h3 id="_4-manifest-requireencryption-—-raise-only" tabindex="-1">4. Manifest <code>requireEncryption</code> — raise-only <a class="header-anchor" href="#_4-manifest-requireencryption-—-raise-only" aria-label="Permalink to &quot;4. Manifest `requireEncryption` — raise-only&quot;">​</a></h3><p>Extend the manifest <code>database</code> object with an optional <code>requireEncryption?: boolean</code>:</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;database&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;isolation&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;isolated&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;requireEncryption&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Semantics:</p><ul><li><strong>Raise-only.</strong> A plugin can force encryption <strong>on</strong> for its own isolated database even when the instance-wide key is set but the plugin author wants to guarantee it. A plugin can <strong>never</strong> turn encryption off. A malicious or careless plugin must not be a downgrade vector.</li><li><strong>Implies isolation.</strong> Whole-file encryption has no per-table granularity, so a <code>requireEncryption</code> plugin&#39;s data must live in its own file. Manifest validation therefore requires <code>isolation: &quot;isolated&quot;</code> alongside <code>requireEncryption: true</code> — a <code>shared</code> plugin declaring it is a manifest error (a <code>shared</code> plugin&#39;s tables live inside <code>sovereign.db</code> and inherit whatever state the platform DB is in; it cannot independently demand more).</li><li><strong>Forces the operator&#39;s hand, loudly.</strong> If a plugin requires encryption and <code>SOVEREIGN_DB_ENCRYPTION_KEY</code> is not set, plugin provisioning / startup fails with a message that <strong>names the plugin</strong>: &quot;Plugin <code>&lt;id&gt;</code> requires database encryption — set <code>SOVEREIGN_DB_ENCRYPTION_KEY</code> to enable it, or remove the plugin.&quot; Never a generic crash.</li></ul><p>This is a new field in <code>packages/manifest</code> (a public contract). Per repo conventions it ships with a <code>docs/plugin-development.md</code> update in the same PR and is covered by the manifest docs-parity test.</p><h3 id="_5-postgres-explicitly-out-of-scope-never-silent" tabindex="-1">5. Postgres: explicitly out of scope, never silent <a class="header-anchor" href="#_5-postgres-explicitly-out-of-scope-never-silent" aria-label="Permalink to &quot;5. Postgres: explicitly out of scope, never silent&quot;">​</a></h3><p>Postgres has no portable app-level equivalent to SQLCipher (same conclusion as RFC 0008). Under Postgres:</p><ul><li><code>SOVEREIGN_DB_ENCRYPTION_KEY</code> applies only to any SQLite files that still exist (none, in a pure-Postgres deployment) and is otherwise a documented no-op.</li><li>A plugin declaring <code>requireEncryption</code> while resolved to a Postgres dialect emits a <strong>startup warning</strong> — not a silent pass — stating that at-rest protection falls back to disk/volume encryption + <code>sslmode</code>, because the SQLCipher mechanism does not exist for Postgres. Silence here would let a plugin&#39;s security promise evaporate invisibly.</li></ul><h3 id="_6-migration-for-existing-plaintext-instances" tabindex="-1">6. Migration for existing plaintext instances <a class="header-anchor" href="#_6-migration-for-existing-plaintext-instances" aria-label="Permalink to &quot;6. Migration for existing plaintext instances&quot;">​</a></h3><p>Enabling encryption on an instance that already has plaintext <code>sovereign.db</code> / <code>auth.db</code> / plugin DBs requires a one-time, offline conversion — a new <code>sv</code> command (e.g. <code>sv db encrypt</code>) that:</p><ol><li>does a best-effort check that no other process holds the file open for writing (not a guarantee — see Open question 5&#39;s resolution — this is why step 2 is required rather than optional);</li><li><strong>requires a fresh backup first</strong> (automatic, same archive format as <code>sv backup</code>, skippable only with an explicit flag);</li><li>copies each SQLite file to a temp path, opens the copy, sets <code>PRAGMA cipher=&#39;sqlcipher&#39;</code>, and calls <code>.rekey()</code> with <code>SOVEREIGN_DB_ENCRYPTION_KEY</code> — <strong>not</strong> <code>sqlcipher_export()</code>, which this driver fork doesn&#39;t implement (see Open question 2&#39;s resolution);</li><li>covers <strong>all</strong> SQLite files: platform, auth, and every isolated plugin DB found under the data dir;</li><li>is crash-tolerant — writes to the temp file and atomically renames it over the original, so a mid-migration failure leaves the plaintext original intact;</li><li>writes the §3 marker only after every file has converted successfully.</li></ol><p>A companion <code>sv db decrypt</code> (reverse direction, <code>.rekey()</code> to an empty key) is needed for two operational paths: rotating to a new key (decrypt → re-encrypt) and the SQLite→Postgres migration below.</p><h3 id="_7-break-glass-cli-seed-and-the-pgloader-path" tabindex="-1">7. Break-glass CLI, seed, and the pgloader path <a class="header-anchor" href="#_7-break-glass-cli-seed-and-the-pgloader-path" aria-label="Permalink to &quot;7. Break-glass CLI, seed, and the pgloader path&quot;">​</a></h3><ul><li><strong><code>sv user reset-mfa</code></strong> (<code>scripts/reset-mfa.ts</code>) opens <code>auth.db</code> directly, by design, for when the server is down. It must read <code>SOVEREIGN_DB_ENCRYPTION_KEY</code> from its own environment and key the connection, with a distinct &quot;encryption key missing/wrong&quot; error — this tool&#39;s entire value is working when everything else is broken, so its failure messages must not look like data corruption to a panicking locked-out admin.</li><li><strong><code>scripts/seed.ts</code></strong> keys its connection the same way for dev parity.</li><li><strong>SQLite→Postgres migration.</strong> <code>docs/self-hosting.md</code> documents pointing <code>pgloader</code> directly at the SQLite files. <code>pgloader</code> has no cipher support, so this path breaks under encryption. The remediation is documented: run <code>sv db decrypt</code> to a temporary plaintext copy, run <code>pgloader</code> against that, then shred the temporary copy.</li></ul><h3 id="_8-backups-become-encrypted-for-free-with-the-standing-caveat" tabindex="-1">8. Backups become encrypted for free (with the standing caveat) <a class="header-anchor" href="#_8-backups-become-encrypted-for-free-with-the-standing-caveat" aria-label="Permalink to &quot;8. Backups become encrypted for free (with the standing caveat)&quot;">​</a></h3><p>Once the files are encrypted, the existing backup mechanisms (copy <code>./data/</code>, snapshot the named volume) produce ciphertext with no additional work — this delivers the DB portion of RFC 0008 Tier 2c as a side effect. The unchanged, prominently-documented caveat: <strong>the key must be backed up separately from the data.</strong> A backup encrypted under a key stored only inside that same backup is worthless. Lose the key → lose the data — the cost of true ownership (NFR-02).</p><h2 id="threat-model" tabindex="-1">Threat model <a class="header-anchor" href="#threat-model" aria-label="Permalink to &quot;Threat model&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Threat</th><th>This RFC</th><th>Notes</th></tr></thead><tbody><tr><td>Stolen disk / leaked volume snapshot</td><td><strong>Yes</strong></td><td>Files are ciphertext without the key.</td></tr><tr><td>Copied/leaked database file</td><td><strong>Yes</strong></td><td>Same.</td></tr><tr><td>Leaked file-copy backup</td><td><strong>Yes</strong></td><td>Backups inherit encryption (§8), if the key is stored separately.</td></tr><tr><td>Curious/malicious operator with the key</td><td>No</td><td>Server-held key; the operator holds it. Use RFC 0060 for this.</td></tr><tr><td>RCE / live compromised process</td><td>No</td><td>The running process has the key in memory. Use RFC 0060 for this.</td></tr><tr><td>Postgres deployments</td><td>No</td><td>No SQLCipher equivalent; rely on disk encryption + <code>sslmode</code>.</td></tr></tbody></table><p>The honest framing is unchanged from RFC 0008: server-held-key at-rest encryption protects data <strong>off</strong> the running host, not from someone who controls the host or holds the key. This RFC does not overstate that.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ol><li><p><strong>Per-database keys instead of one instance key.</strong> Safer in principle (a leaked key unlocks one database, not all). Rejected for v1 of this feature per the operator&#39;s explicit simplification: one key is far easier to configure, back up, and rotate, and the marginal safety gain is small given all keys would live in the same env on the same host anyway. Can be revisited later without changing the on-disk format (each file is independently keyed under the hood; today they simply share one key value).</p></li><li><p><strong>The full RFC 0008 Tier 2 KEK→DEK envelope.</strong> More flexible (rotation re-wraps small DEKs instead of re-encrypting files). Deferred — it is the reason Tier 2 keeps slipping. This RFC ships the achievable 80% now; the envelope hierarchy remains available in Task 8.5 if per-DB keys or cheap rotation become requirements.</p></li><li><p><strong>A separate <code>SOVEREIGN_DB_ENCRYPTION=on/off</code> boolean plus a key.</strong> Rejected as redundant — presence of the key is a clearer single source of truth and matches the existing no-default-secret convention. The §3 marker handles mismatch detection that a boolean would otherwise be misused for.</p></li><li><p><strong>Whole-DB encryption but let a plugin opt <em>out</em> via manifest.</strong> Rejected — a plugin must never weaken the operator&#39;s instance-wide setting. The manifest control is raise-only.</p></li><li><p><strong>Full-disk / volume encryption only (no app-level).</strong> The current documented posture. Necessary but insufficient: it does nothing against a leaked logical copy of a single <code>.db</code> file, and many operators on managed hosting cannot easily configure it. Kept as complementary baseline, not a replacement.</p></li><li><p><strong>Field-level encryption for &quot;sensitive&quot; columns instead.</strong> That is RFC 0008 Tier 3 — far more engineering (breaks search/sort, needs blind indexes, new SDK surface) for a benefit whole-file encryption already covers at the page level. Remains separately in Task 8.5.</p></li></ol><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><p>Resolved during implementation:</p><ol><li><strong>Marker mechanism</strong> — implemented as a sentinel file (<code>data/.db-encrypted</code>), matching the leaning noted here. Lives inside the data directory, so it travels with backups automatically (resolves question 7 too).</li><li><strong>Keying pragma specifics — resolved, and this mattered more than expected.</strong> <code>better-sqlite3-multiple-ciphers</code> supports several cipher schemes and <strong>defaults to its own (&quot;sqleet&quot;), not SQLCipher.</strong> Early implementation work used the default without realizing it; empirical testing (attempting the driver&#39;s <code>sqlcipher_export()</code> — which turned out not to exist in this fork at all, unlike upstream SQLCipher) surfaced the mismatch. Fixed by explicitly setting <code>PRAGMA cipher=&#39;sqlcipher&#39;</code> before <code>.key()</code>/<code>.rekey()</code> at every call site, so the on-disk format is genuinely SQLCipher-compatible as this RFC&#39;s title promises. No <code>legacy=</code> pragma needed — this driver&#39;s default <code>legacy</code> value already matches current SQLCipher 4.x KDF parameters.</li><li><strong>Isolated plugin DB discovery</strong> — implemented via data-dir scanning (<code>data/plugins/*.db</code>), not the registry. Simpler, and catches orphaned plugin databases the registry no longer lists.</li><li><strong>Rotation UX — resolved via in-place rekey, not decrypt→re-encrypt.</strong><code>sv db encrypt</code>/<code>decrypt</code> both use the driver&#39;s <code>.rekey()</code> method internally (copy to temp → rekey the copy → atomic rename over the original), so rotation is <code>sv db decrypt</code> (old key) followed by <code>sv db encrypt</code> (new key) — no separate <code>sv db rekey</code> command needed.</li><li><strong>Performance against NFR-07 — partially measured, not yet on target hardware.</strong> A relative micro-benchmark (20k-row write/read) showed encrypted writes taking roughly 70-85% longer than plaintext, reads effectively unaffected — measured on ordinary dev hardware, not the 2-core/1GB VPS NFR-07 targets. Worth a real benchmark there before recommending this broadly to resource-constrained operators.</li><li><strong>better-auth under the cipher driver — confirmed working end to end.</strong> Exercised directly: <code>runAuthMigrations()</code> (better-auth&#39;s own <code>getMigrations</code>/<code>runMigrations</code>) plus insert/read against a <code>sqlcipher</code>-keyed <code>auth.db</code>, verified genuine ciphertext on disk. Full HTTP-level sign-in/MFA flow was not exercised (would need a running server); the DB-layer compatibility that was the actual risk is confirmed.</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><p>Implemented (epic task 8.14):</p><ol><li><strong>Phase A — spike / de-risk.</strong> Swapped <code>better-sqlite3-multiple-ciphers</code> in for <code>packages/db/src/client.ts</code>; ran the full test suite; verified genuine ciphertext and correct/wrong/missing-key behavior; measured relative overhead. Surfaced the cipher-default issue (open question 2) before it spread to every call site.</li><li><strong>Phase B — key primitive.</strong> <code>SOVEREIGN_DB_ENCRYPTION_KEY</code> loader (mirrors <code>decodeKey</code>/fail-fast from <code>secrets.ts</code>); the shared keyed opener (<code>packages/db/src/sqlite-encryption.ts</code> + the <code>apps/auth</code> self-contained twin); the §3 marker + mismatch guard, both directions.</li><li><strong>Phase C — wired all five call sites</strong> (<code>client.ts</code>, <code>plugin-client.ts</code>, <code>apps/auth/src/db.ts</code>, <code>reset-mfa.ts</code>, <code>seed.ts</code>), each with clear key-mismatch errors. Verified better-auth&#39;s own migrator against an encrypted <code>auth.db</code> (resolves open question 6).</li><li><strong>Phase D — manifest <code>requireEncryption</code></strong> (raise-only, implies isolated, enforced both at manifest-validation time and at runtime plugin-migration time — the latter fails startup naming the plugin for SQLite, warns for Postgres) + <code>docs/plugin-development.md</code> + docs-parity. Additive manifest field → <strong>minor</strong> version bump for <code>@sovereignfs/manifest</code>.</li><li><strong>Phase E — migration tooling.</strong> <code>sv db encrypt</code> / <code>sv db decrypt</code> (automatic pre-conversion backup, crash-tolerant atomic swap per file, best-effort live-server lock probe, covers all SQLite files including isolated plugin DBs) — validated end to end via live CLI runs, not just unit tests.</li><li><strong>Phase F — docs + Docker.</strong> <code>.env.example</code>, <code>docs/self-hosting.md</code> (new env var, full usage section, rotation, the pgloader-replacement note), <code>docs/security.md</code> (threat-model row and checklist updated to reflect this as shipped, not just specified), <code>docs/plugin-development.md</code> (<code>requireEncryption</code>), both Dockerfiles&#39; toolchain comments, both <code>docker-compose*.yml</code> files (env var pass-through on both services), <code>pnpm-workspace.yaml</code> <code>allowBuilds</code>. <code>docs-parity</code> passes.</li></ol><p>No published-SDK (<code>@sovereignfs/sdk</code>) surface changes; the only public-contract change is the additive manifest field (Phase D). Per-package version bumps: <code>@sovereignfs/db</code> (new encryption/migration surface), <code>@sovereignfs/manifest</code> (new field), <code>@sovereignfs/auth</code> and <code>runtime</code> (wired consumers) — all minor; platform version minor-bumped per the roadmap-milestone convention.</p><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>July 2026</td><td>Initial draft — opt-in, single-key SQLite whole-file at-rest encryption carved out of RFC 0008 Tier 2b; manifest <code>requireEncryption</code> (raise-only); migration tooling; explicit Postgres no-op-with-warning.</td></tr><tr><td>1.0</td><td>July 2026</td><td>Implemented (epic task 8.14), all six adoption phases. Notably corrected the cipher selection mid-implementation — the driver&#39;s default is not SQLCipher, <code>cipher=&#39;sqlcipher&#39;</code> must be set explicitly (open question 2). Migration tooling uses in-place <code>.rekey()</code>, not <code>sqlcipher_export()</code> (that function doesn&#39;t exist in this driver fork). better-auth migration compatibility confirmed empirically.</td></tr><tr><td>1.1</td><td>July 2026</td><td>Fixed the §3 marker guard: &quot;marker absent, key present&quot; was treated as always meaning pre-existing plaintext data, with no exception for a genuinely empty data directory — silently breaking the &quot;Enabling on a fresh instance&quot; onboarding path this RFC documents (<code>sv db encrypt</code> also found zero files there and skipped writing the marker, so following the guard&#39;s own error led to a dead end). Added the fifth table row above; verified via a full local stress test covering fresh-instance boot, existing-instance encrypt/decrypt round-trip, wrong-key rejection, key rotation, and the CLI idempotency guards.</td></tr></tbody></table>',63)])])}const g=t(s,[["render",n]]);export{u as __pageData,g as default};
